#[cfg(test)]
mod tests {
    use std::collections::BTreeMap;

    use super::*;

    #[test]
    fn seeded_snapshot_respects_the_configured_active_threshold() {
        let now = now_unix();
        let policy = config::DecayPolicy {
            half_life_overrides: BTreeMap::new(),
            prune_threshold: 0.6,
        };
        let engine = MindLeak::open_in_memory()
            .unwrap()
            .with_decay_policy(policy);
        engine
            .store()
            .upsert_node(&Node::new("artifact:a", NodeType::Artifact, "a", now))
            .unwrap();
        engine
            .store()
            .upsert_node(&Node::new("artifact:b", NodeType::Artifact, "b", now))
            .unwrap();
        engine
            .store()
            .upsert_edge(&Edge {
                source_id: "artifact:a".to_string(),
                target_id: "artifact:b".to_string(),
                relation: RelationType::Modified,
                weight: 0.5,
                half_life_hours: 24.0,
                updated_at: now,
            })
            .unwrap();

        let snapshot = engine.snapshot(Some("artifact:a"), 10).unwrap();

        assert!(snapshot.edges.is_empty());
    }

    #[test]
    fn working_set_requires_identity_and_enforces_the_configured_cap() {
        let without_agent = MindLeak::open_in_memory().unwrap();
        assert!(without_agent.working_set(None).is_err());

        let engine = MindLeak::open_in_memory()
            .unwrap()
            .with_working_set_size(1)
            .with_agent(Some("agent:agent-a".to_string()));
        engine.ingest_file("src/a.rs", "fn a() {}\n").unwrap();
        engine.ingest_file("src/b.rs", "fn b() {}\n").unwrap();

        let working = engine.working_set(Some(32)).unwrap();
        assert_eq!(working.len(), 1);
        assert!(working[0].node.id.starts_with("artifact:"));
    }
}
